// Detect language from URL param, then browser, default to 'en'
let currentLang = (() => {
  const urlLang = new URLSearchParams(window.location.search).get('lang');
  if (urlLang && translations[urlLang]) return urlLang;
  const browserLang = (navigator.language || '').split('-')[0];
  if (translations[browserLang]) return browserLang;
  return 'en';
})();

function t(key, params) {
  const str = (translations[currentLang] && translations[currentLang][key]) || translations.en[key] || key;
  if (!params) return str;
  return str.replace(/\{(\w+)\}/g, (_, k) => params[k] !== undefined ? params[k] : `{${k}}`);
}

function dateLocale() { return currentLang === 'es' ? 'es-ES' : 'en-US'; }

function setLanguage(lang) {
  if (!translations[lang]) return;
  currentLang = lang;
  const u = new URL(window.location);
  u.searchParams.set('lang', lang);
  window.history.replaceState({}, '', u);
  document.documentElement.lang = lang;
  rebuildUI();
}

function rebuildUI() {
  // Update static HTML elements with translations
  // Nav
  const navLinks = document.querySelector('.nav-links');
  if (navLinks) navLinks.innerHTML = `<a href="#">${t('home')}</a><a href="#">${t('about')}</a><a href="#" class="active">${t('screenings')}</a><a href="#">${t('donate')}</a><a href="#">${t('press')}</a><a href="#">${t('contact')}</a>`;

  // Language switcher active state
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.toggle('active', b.dataset.lang === currentLang));

  // Region toggle
  const regionToggle = document.getElementById('regionToggle');
  if (regionToggle) regionToggle.innerHTML = `<button class="region-toggle-btn ${regionFilter==='worldwide'?'active':''}" data-region="worldwide"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M2 12h20"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>${t('worldwide')}</button><button class="region-toggle-btn ${regionFilter==='guatemala'?'active':''}" data-region="guatemala"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>${t('guatemala')}</button>`;

  // Filter buttons
  const timeFilters = document.getElementById('timeFilters');
  if (timeFilters) timeFilters.innerHTML = `<button class="filter-btn active" data-filter="all">${t('all')}</button><button class="filter-btn" data-filter="upcoming">${t('upcoming')}</button><button class="filter-btn" data-filter="past">${t('past')}</button>`;

  // Search
  const searchInput = document.getElementById('searchInput');
  if (searchInput) searchInput.placeholder = t('searchPlaceholder');

  // Sort dropdown i18n
  const sortMenu = document.getElementById('sortMenu');
  if (sortMenu) {
    const items = sortMenu.querySelectorAll('.sort-dropdown-item');
    const labels = { featured: t('featured'), 'date-asc': t('dateAsc'), 'date-desc': t('dateDesc'), distance: t('distance') };
    items.forEach(item => { item.textContent = labels[item.dataset.value] || item.textContent; });
    const activeItem = sortMenu.querySelector('.sort-dropdown-item.active');
    const sortBtn = document.getElementById('sortBtn');
    if (activeItem && sortBtn) sortBtn.textContent = activeItem.textContent;
  }


  // Type filters
  const typeRow = document.getElementById('typeFilterRow');
  if (typeRow) typeRow.innerHTML = `<button class="filter-btn active" data-type="all">${t('allTypes')}</button><button class="filter-btn" data-type="festival">${t('festival')}</button><button class="filter-btn" data-type="special">${t('specialScreening')}</button>`;

  // View toggles
  document.querySelectorAll('.view-toggle').forEach(b => {
    const v = b.dataset.view;
    if (v === 'list') b.title = t('listView');
    if (v === 'hybrid') b.title = t('hybridView');
    if (v === 'map') b.title = t('mapView');
  });

  // Rebind filter events (since innerHTML replaced the buttons)
  bindFilterEvents();

  // Re-render dynamic content
  renderList();
  if (map) { addMapMarkers(); }
}

