// ===== STREAMING HELPERS =====
function parseDate(str) {
  let d = str.split('–')[0].split('\u2013')[0].trim();
  if (!/\d{4}/.test(d)) d += ', 2026';
  const dt = new Date(d); dt.setHours(0,0,0,0); return dt;
}
function getStreamStatus(online) {
  if (!online) return null;
  const today = new Date(); today.setHours(0,0,0,0);
  const start = new Date(online.start); start.setHours(0,0,0,0);
  const end = new Date(online.end); end.setHours(23,59,59,999);
  const diffStart = Math.round((start - today) / (1000*60*60*24));
  if (today > end) return null; // Don't show past streaming periods
  if (today >= start && today <= end) return { status: 'live', label: t('streamingNow'), cssClass: 'stream-live' };
  if (diffStart === 0) return { status: 'live', label: t('streamingNow'), cssClass: 'stream-live' };
  if (diffStart === 1) return { status: 'upcoming', label: t('availableOnlineTomorrow'), cssClass: 'stream-upcoming' };
  if (diffStart <= 7) return { status: 'upcoming', label: t('availableOnlineInDays', {n: diffStart}), cssClass: 'stream-upcoming' };
  return { status: 'upcoming', label: t('onlineDate', {date: start.toLocaleDateString(dateLocale(),{month:'short',day:'numeric'})}), cssClass: 'stream-upcoming' };
}
function isOnlineOnly(ev) {
  return ev.online && (ev.lat === 0 && ev.lng === 0);
}
function buildStreamBadge(ev) {
  const ss = getStreamStatus(ev.online);
  if (!ss) return '';
  const globeSvg = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M2 12h20"/><path d="M12 2a15.3 15.3 0 014 10 15.3 15.3 0 01-4 10 15.3 15.3 0 01-4-10 15.3 15.3 0 014-10z"/></svg>`;
  const lockSvg = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>`;
  let geoHtml = '';
  if (ev.online.geoLabel) {
    const icon = ev.online.geo === 'worldwide' ? globeSvg : lockSvg;
    geoHtml = `<div class="stream-geo">${icon}${ev.online.geoLabel}</div>`;
  }
  return `<div class="stream-badge ${ss.cssClass}">${globeSvg}${ss.label}</div>${geoHtml}`;
}
// Check if an online event's geo covers a given country code
function onlineCoversRegion(online, searchText) {
  if (!online) return false;
  if (online.geo === 'worldwide') return true;
  const geo = online.geo.toLowerCase();
  const q = searchText.toLowerCase();
  // Simple: check if the geoLabel or geo string contains relevant terms
  if (online.geoLabel && online.geoLabel.toLowerCase().includes(q)) return true;
  // Check country code matches
  const countryCodes = { 'united states':'US','us':'US','usa':'US','colorado':'US','california':'US','new york':'US','texas':'US',
    'canada':'CA','mexico':'MX','australia':'AU','uk':'GB','united kingdom':'GB','chile':'CL','guatemala':'GT',
    'spain':'ES','austria':'AT','scotland':'GB','france':'FR','germany':'DE' };
  const code = countryCodes[q];
  if (code && geo.includes(code.toLowerCase())) return true;
  return false;
}

// ===== SMART COUNTDOWN LABEL =====
function getUpcomingLabel(ev) {
  if (!ev.upcoming) return '';
  // Online-only events get streaming label
  if (isOnlineOnly(ev)) {
    const ss = getStreamStatus(ev.online);
    if (ss) {
      if (ss.status === 'live') return t('streamingNow') + '!';
      return ss.label;
    }
  }
  const firstScreening = ev.screenings[0];
  if (!firstScreening) return t('upcomingFallback');
  const screenDate = parseDate(firstScreening.date);
  const today = new Date(); today.setHours(0,0,0,0);
  const diffDays = Math.round((screenDate - today) / (1000*60*60*24));

  if (diffDays < 0) return t('screeningRecently');
  if (diffDays === 0) return t('screeningToday');
  if (diffDays === 1) return t('screeningTomorrow');
  if (diffDays <= 6) {
    const dayName = screenDate.toLocaleDateString(dateLocale(), { weekday: 'long' });
    return t('screeningThisDay', { day: dayName });
  }
  if (diffDays <= 30) return t('screeningInDays', { n: diffDays });
  return t('screeningOnDate', { date: screenDate.toLocaleDateString(dateLocale(), { month: 'short', day: 'numeric' }) });
}

// ===== HAVERSINE DISTANCE =====
function haversineDistance(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLng/2) * Math.sin(dLng/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

