// ===== CAROUSEL =====
function getSlideIndex(id) { return carouselStates[id] || 0; }

function setSlide(evId, delta, e) {
  if (e) { e.stopPropagation(); e.preventDefault(); }
  const ev = events.find(x => x.id === evId);
  if (!ev || ev.upcoming) return;
  const totalSlides = getEventSlideCount(ev);
  let idx = (getSlideIndex(evId) + delta + totalSlides) % totalSlides;
  carouselStates[evId] = idx;
  document.querySelectorAll(`[data-carousel="${evId}"] .carousel-track, [data-carousel="${evId}"] .popup-carousel-track`).forEach(track => {
    track.style.transform = `translateX(-${idx * 100}%)`;
  });
  document.querySelectorAll(`[data-carousel="${evId}"] .carousel-dot`).forEach((dot, i) => {
    dot.classList.toggle('active', i === idx);
  });
}

function startAutoAdvance(evId) {
  stopAutoAdvance(evId);
  const ev = events.find(x => x.id === evId);
  if (!ev || ev.upcoming) return;
  const totalSlides = getEventSlideCount(ev);
  if (totalSlides <= 1) return;
  autoAdvanceTimers[evId] = setInterval(() => { setSlide(evId, 1, null); }, 2200);
}
function stopAutoAdvance(evId) {
  if (autoAdvanceTimers[evId]) { clearInterval(autoAdvanceTimers[evId]); delete autoAdvanceTimers[evId]; }
}

function getEventSlideCount(ev) {
  if (ev.eventImages && ev.eventImages.length > 0) {
    const photosExtra = (ev.photos && !ev.eventImages.includes(ev.photos)) ? 1 : 0;
    return photosExtra + ev.eventImages.length;
  }
  return 1; // single slide: either image or hero text
}
