// ===== Hook into location events =====
// Wrap setLocationChip to trigger banner
const _origSetLocationChip = setLocationChip;
setLocationChip = function(name, lat, lng) {
  _origSetLocationChip(name, lat, lng);
  showNotifyBanner(name);
};

// Wrap clearLocationChip to hide banner
const _origClearLocationChip = clearLocationChip;
clearLocationChip = function() {
  _origClearLocationChip();
  hideNotifyBanner();
};

